#include <stdio.h>
#include <string.h>
#include <unistd.h>
#include <errno.h>
#include <fcntl.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <sys/wait.h>

int main(void) {
    int sv[2];
    socketpair(AF_UNIX, SOCK_STREAM, 0, sv);
    int flags = fcntl(sv[0], F_GETFL, 0);
    fcntl(sv[0], F_SETFL, flags | O_NONBLOCK);
    char buf[64];
    int n = recv(sv[0], buf, sizeof(buf), 0);
    if (n < 0 && (errno == EAGAIN || errno == EWOULDBLOCK))
        printf("recv: EAGAIN (no data)\n");
    send(sv[1], "DATA", 4, 0);
    n = recv(sv[0], buf, sizeof(buf) - 1, 0);
    buf[n] = '\0';
    printf("recv: %s\n", buf);
    close(sv[0]);
    close(sv[1]);
    return 0;
}

